SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND (t.Close/ NULLIF(t.Volume_MaxTop5_2Y_Close, 0) < 0.84) AND (t.ID_Current - t.Volume_MaxTop5_2Y_ID <=128.0) AND (t.Close < 1.17*t.VAP1W) AND (t.D_RSI < 0.55) AND (t.Close/ NULLIF(t.Close_T1, 0) < 1.1) AND (t.D_RSI/ NULLIF(t.D_RSI_T1W, 0) < 1.03) AND (t.Close_T1/ NULLIF(t.LO_3M_T1, 0) > 1.59) ORDER BY t.ticker, t.time